	require.NoError(t, err)
	assert.Equal(t, 2, count)

	gotA, err := dst.Get(a.ID)
	require.NoError(t, err)
	assert.Equal(t, "alpha", gotA.Title)

	gotB, err := dst.Get(bb.ID)
	require.NoError(t, err)
